                ClassName    = $tc.classname
                Status       = $status
                Duration     = [double]$tc.time
                ErrorMessage = $errorMessage
            }
        }
    }

    # Return normalized result object
    [PSCustomObject]@{
        TestCases     = $testCases
        TotalDuration = [double]$root.time
    }
}

